use crate::decoders::{Crack, CrackResult, Decoder, check_string_success};use crate::checkers::CheckerTypes;use data_encoding::BASE32;use std::marker::PhantomData;pub struct Base32Decoder;impl Crack for Decoder<Base32Decoder> {    fn crack(&self, text: &str, checker: &CheckerTypes) -> CrackResult {        let mut result = CrackResult::new(self.get_name(), self.get_description(), self.get_link());        result.encrypted_text = text.to_string();        let text_upper = text.to_uppercase();        if let Ok(decoded_bytes) = BASE32.decode(text_upper.as_bytes()) {            if let Ok(decoded_str) = String::from_utf8(decoded_bytes) {                if check_string_success(&decoded_str, text) {                    let check_result = checker.check_text(&decoded_str);                    if check_result.is_identified {                        result.success = true;                        result.unencrypted_text = Some(vec![decoded_str]);                        result.checker_name = check_result.checker_name;                        return result;                    }                }            }        }        result    }    fn get_name(&self) -> &'static str { "Base32" }    fn get_popularity(&self) -> f32 { 0.7 }    fn get_tags(&self) -> &'static [&'static str] { &["base32", "decoder", "base"] }    fn get_description(&self) -> &'static str { "Base32 is a notation for encoding arbitrary byte data using a 32-character alphabet." }    fn get_link(&self) -> &'static str { "https://en.wikipedia.org/wiki/Base32" }}impl Decoder<Base32Decoder> {    pub fn new() -> Self {        Decoder {            name: "Base32",            description: "Base32 is a notation for encoding arbitrary byte data using a 32-character alphabet.",            link: "https://en.wikipedia.org/wiki/Base32",            tags: vec!["base32", "decoder", "base"],            popularity: 0.7,            phantom: PhantomData,        }    }}



